   122→		if _, ok := groupVersionMatchers[key]; ok {
   123→			continue
   124→		}
   125→
   126→		tokens := strings.Split(key, "/")
   127→		if len(tokens) < 2 || len(tokens) > 3 {
   128→			continue
   129→		}
   130→		groupVersionString := tokens[0] + "/" + tokens[1]
